import { Component, HostListener, OnDestroy } from '@angular/core';
import { CommonModule } from '@angular/common';

type Direction = 'UP' | 'DOWN' | 'LEFT' | 'RIGHT';
interface Point { x: number; y: number }

const BOARD_SIZE = 14;
const STEP_MS = 140;
const INITIAL_SNAKE: Point[] = [
  { x: 6, y: 7 },
  { x: 5, y: 7 },
  { x: 4, y: 7 }
];
const INITIAL_FOOD: Point = { x: 8, y: 7 };

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnDestroy {
  readonly boardSize = BOARD_SIZE;
  snake: Point[] = INITIAL_SNAKE.map((point) => ({ ...point }));
  direction: Direction = 'RIGHT';
  bufferedDirection: Direction | null = null;
  food: Point | null = { ...INITIAL_FOOD };
  isRunning = false;
  isGameOver = false;
  isWon = false;
  score = 0;
  private timerId: ReturnType<typeof setInterval> | null = null;

  get length(): number { return this.snake.length; }
  get statusLabel(): string {
    if (this.isWon) return 'You win';
    if (this.isGameOver) return 'Game over';
    return this.isRunning ? 'Running' : 'Paused';
  }

  @HostListener('window:keydown', ['$event'])
  onKeydown(event: KeyboardEvent): void {
    const key = String(event.key || '').toLowerCase();
    // TODO: Map Arrow/WASD keys. Accept at most one perpendicular turn per tick.
    // Validate against direction, not another key queued during the same tick.
    // Invalid same/opposite keys must not consume the buffer.
    // Space toggles play; Enter resets either terminal state.
    void key;
  }

  toggleRunning(): void {
    if (this.isGameOver || this.isWon) return;
    this.isRunning ? this.pause() : this.start();
  }
  start(): void { /* TODO: own one 140 ms interval. */ }
  pause(): void { /* TODO: stop the interval and set running false. */ }
  reset(): void { /* TODO: restore snake, direction, null buffer, food, score, and terminal flags. */ }

  isSnake(x: number, y: number): boolean {
    return this.snake.some((point) => point.x === x && point.y === y);
  }
  isHead(x: number, y: number): boolean {
    const head = this.snake[0];
    return head.x === x && head.y === y;
  }
  isFood(x: number, y: number): boolean {
    return this.food !== null && this.food.x === x && this.food.y === y;
  }
  trackByIndex(index: number): number { return index; }

  ngOnDestroy(): void { this.clearTimer(); }

  private tick(): void {
    // TODO: Commit bufferedDirection ?? direction, then clear the buffer.
    // TODO: Check wall/body collision before mutating state.
    // TODO: On food, grow and choose a free cell. If none exists, set food null,
    // mark isWon, and stop the interval without also marking game over.
  }

  private clearTimer(): void {
    if (this.timerId !== null) {
      clearInterval(this.timerId);
      this.timerId = null;
    }
  }
}

