import { TestBed, discardPeriodicTasks, fakeAsync, tick } from '@angular/core/testing';
import { AppComponent } from './app.component';

const STEP_MS = 140;
type Direction = 'UP' | 'DOWN' | 'LEFT' | 'RIGHT';
type Point = { x: number; y: number };
type TestAppComponent = AppComponent & {
  snake: Point[];
  direction: Direction;
  bufferedDirection: Direction | null;
  food: Point | null;
};

function createComponent() {
  TestBed.configureTestingModule({ imports: [AppComponent] });
  const fixture = TestBed.createComponent(AppComponent);
  fixture.detectChanges();
  return { fixture, component: fixture.componentInstance as TestAppComponent };
}

function press(component: AppComponent, key: string): void {
  component.onKeydown(new KeyboardEvent('keydown', { key }));
}

describe('Angular Snake Game', () => {
  it('renders the initial 14x14 board, snake, and deterministic food', () => {
    const { fixture, component } = createComponent();
    expect(fixture.nativeElement.querySelectorAll('.cell').length).toBe(196);
    expect(component.snake).toEqual([
      { x: 6, y: 7 }, { x: 5, y: 7 }, { x: 4, y: 7 }
    ]);
    expect(component.food).toEqual({ x: 8, y: 7 });
    fixture.destroy();
  });

  it('does not move before the first 140 ms tick', fakeAsync(() => {
    const { fixture, component } = createComponent();
    component.start();
    tick(STEP_MS - 1);
    expect(component.snake[0]).toEqual({ x: 6, y: 7 });
    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('buffers only the first valid turn in RIGHT -> UP -> LEFT during one tick', fakeAsync(() => {
    const { fixture, component } = createComponent();
    component.start();
    press(component, 'ArrowUp');
    press(component, 'ArrowLeft');
    tick(STEP_MS);
    expect(component.snake[0]).toEqual({ x: 6, y: 6 });
    expect(component.direction).toBe('UP');
    expect(component.bufferedDirection).toBeNull();
    expect(component.isGameOver).toBeFalse();
    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('does not let an invalid key consume the one-turn buffer', fakeAsync(() => {
    const { fixture, component } = createComponent();
    component.start();
    press(component, 'ArrowLeft');
    press(component, 'ArrowUp');
    tick(STEP_MS);
    expect(component.snake[0]).toEqual({ x: 6, y: 6 });
    expect(component.direction).toBe('UP');
    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('grows at 280 ms, increments score, and places food off the snake', fakeAsync(() => {
    const { fixture, component } = createComponent();
    component.start();
    tick(STEP_MS * 2);
    expect(component.score).toBe(1);
    expect(component.snake.length).toBe(4);
    expect(component.snake[0]).toEqual({ x: 8, y: 7 });
    expect(component.food).not.toBeNull();
    expect(component.snake.some((part) => part.x === component.food?.x && part.y === component.food?.y)).toBeFalse();
    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('wins and stops with no food when the final free cell is eaten', fakeAsync(() => {
    const { fixture, component } = createComponent();
    const remaining = { x: 13, y: 13 };
    const allOccupied = Array.from({ length: 196 }, (_, index) => ({
      x: index % 14,
      y: Math.floor(index / 14)
    })).filter((point) => point.x !== remaining.x || point.y !== remaining.y);
    const head = { x: 12, y: 13 };
    component.snake = [head, ...allOccupied.filter((point) => point.x !== head.x || point.y !== head.y)];
    component.direction = 'RIGHT';
    component.bufferedDirection = null;
    component.food = remaining;
    component.start();
    tick(STEP_MS);
    fixture.detectChanges();
    expect(component.snake.length).toBe(196);
    expect(component.food).toBeNull();
    expect(component.isWon).toBeTrue();
    expect(component.isGameOver).toBeFalse();
    expect(component.isRunning).toBeFalse();
    expect(fixture.nativeElement.textContent).toContain('You win');
    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('ends on a wall collision and does not schedule more movement', fakeAsync(() => {
    const { fixture, component } = createComponent();
    component.snake = [{ x: 13, y: 7 }, { x: 12, y: 7 }, { x: 11, y: 7 }];
    component.direction = 'RIGHT';
    component.bufferedDirection = null;
    component.start();
    tick(STEP_MS * 3);
    expect(component.isGameOver).toBeTrue();
    expect(component.snake[0]).toEqual({ x: 13, y: 7 });
    expect(component.isRunning).toBeFalse();
    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('reset restores the buffer, terminal state, timer state, and food', fakeAsync(() => {
    const { fixture, component } = createComponent();
    component.start();
    press(component, 'ArrowUp');
    tick(STEP_MS);
    component.reset();
    expect(component.snake[0]).toEqual({ x: 6, y: 7 });
    expect(component.direction).toBe('RIGHT');
    expect(component.bufferedDirection).toBeNull();
    expect(component.food).toEqual({ x: 8, y: 7 });
    expect(component.score).toBe(0);
    expect(component.isRunning).toBeFalse();
    expect(component.isGameOver).toBeFalse();
    expect(component.isWon).toBeFalse();
    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('cleans up its interval on destroy', fakeAsync(() => {
    const clearIntervalSpy = spyOn(window, 'clearInterval').and.callThrough();
    const { fixture, component } = createComponent();
    component.start();
    fixture.destroy();
    expect(clearIntervalSpy).toHaveBeenCalled();
    discardPeriodicTasks();
  }));
});
